    def fetch_tickers(self, symbols: Strings = None, params={}) -> Tickers:
        """
        fetches price tickers for multiple markets
        https://new-api.bidarz.ir/v1/arz-digital/spot/markets
        https://new-api.bidarz.ir/v1/arz-digital/otc/markets
        :param str[]|None symbols: unified symbols of the markets to fetch the ticker for, all market tickers are returned if not assigned
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :returns dict: a dictionary of `ticker structures <https://docs.ccxt.com/#/?id=ticker-structure>`
        """
        self.load_markets()
        if symbols is not None:
            symbols = self.market_symbols(symbols)
        result = {}
        spotResponse = self.publicGetV1ArzDigitalSpotMarkets(params)
        spotData = self.safe_dict(spotResponse, 'data', {})
        spotSymbols = self.safe_dict(spotData, 'symbols', {})
        spotIds = list(spotSymbols.keys())
        for i in range(0, len(spotIds)):
            ticker = self.parse_ticker(spotSymbols[spotIds[i]], None, 'spot')
            result[ticker['symbol']] = ticker
        otcResponse = self.publicGetV1ArzDigitalOtcMarkets(params)
        otcData = self.safe_dict(otcResponse, 'data', {})
        otcSymbols = self.safe_dict(otcData, 'symbols', {})
        otcIds = list(otcSymbols.keys())
        for i in range(0, len(otcIds)):
            ticker = self.parse_ticker(otcSymbols[otcIds[i]], None, 'otc')
            result[ticker['symbol']] = ticker
        return self.filter_by_array_tickers(result, 'symbol', symbols)

    def fetch_ticker(self, symbol: str, params={}) -> Ticker:
        """
        fetches a price ticker, defaulting duplicate raw spot/OTC symbols to the spot market
        https://new-api.bidarz.ir/v1/arz-digital/spot/markets
        :param str symbol: unified symbol of the market to fetch the ticker for
        :param dict [params]: extra parameters specific to the exchange API endpoint
        :returns dict: a `ticker structure <https://docs.ccxt.com/#/?id=ticker-structure>`
        """
        ticker = self.fetch_tickers([symbol], params)
        return ticker[symbol]

    def parse_ticker(self, ticker, market: Market = None, type='spot') -> Ticker:
        isOtc = (type == 'otc')
        marketId = self.safe_string(ticker, 'symbol')
        if isOtc:
            marketId += ':OTC'
        symbol = self.safe_symbol(marketId, market)
        last = self.convert_price(self.safe_string(ticker, 'price'))
        bid = self.convert_price(self.safe_string(ticker, 'sellPrice'))
        ask = self.convert_price(self.safe_string(ticker, 'buyPrice'))
        high = self.convert_price(self.safe_string(ticker, 'maxPrice24h'))
        low = self.convert_price(self.safe_string(ticker, 'minPrice24h'))
        open = self.convert_price(self.safe_string(ticker, 'price24h'))
        quoteVolume = self.convert_price(self.safe_string(ticker, 'volume24h'))
        close = last
        if isOtc:
            close = None
        return self.safe_ticker({
            'symbol': symbol,
            'timestamp': None,
            'datetime': None,
            'high': high,
            'low': low,
            'bid': bid,
            'bidVolume': None,
            'ask': ask,
            'askVolume': None,
            'vwap': None,
            'open': open,
            'close': close,
            'last': close,
            'previousClose': None,
            'change': None,
            'percentage': None,
            'average': None,
            'baseVolume': None,
            'quoteVolume': quoteVolume,
            'info': ticker,
        }, market)

    def convert_price(self, price):
        value = self.parse_number(price)
        return None if (value is None) else value / 10

    def sign(self, path, api='public', method='GET', params={}, headers=None, body=None):
        query = self.omit(params, self.extract_params(path))
        url = self.urls['api'][api] + '/' + self.implode_params(path, params)
        if query:
            url += '?' + self.urlencode(query)
        headers = {'Content-Type': 'application/json'}
        return {'url': url, 'method': method, 'body': body, 'headers': headers}
